const SCHOOL_EMAIL = "itqanschule@gmail.com";
const ADMIN_EMAIL  = "hassan.nofal@student.medicalschool-berlin.de";
const YEAR         = "2026/2027";
const SHEET_NAME   = "Enrollments";
const FOLDER_NAME  = "Itqan_Dateien";

// ألوان الكارت الأصلي
const CARD_BLUE_DARK  = "#365F91";
const CARD_BLUE_MID   = "#4F81BD";
const CARD_SIDE_W     = 30;   // عرض الشريط الجانبي بالنقاط

// ألوان العقد
const CONTRACT_BLUE   = "#1A3A6B";
const CONTRACT_LIGHT  = "#CDD4E9";

const LOGO_B64 = "

";

// ───────────────────────────────────────────────────────────
function doPost(e) {
  try {
    const data = JSON.parse(e.postData.contents);
    saveToSheet(data);
    const contractPDF = generateContractPDF(data);
    const cardPDFs    = generateAllCardPDFs(data);
    sendEmails(data, contractPDF, cardPDFs);
    return ContentService
      .createTextOutput(JSON.stringify({ status: "ok" }))
      .setMimeType(ContentService.MimeType.JSON);
  } catch(err) {
    Logger.log("ERROR: " + err.toString() + "\n" + err.stack);
    return ContentService
      .createTextOutput(JSON.stringify({ status: "error", message: err.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

// ───────────────────────────────────────────────────────────
//  حفظ البيانات في Google Sheet
// ───────────────────────────────────────────────────────────
function saveToSheet(data) {
  const ss  = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_NAME);

  if (!sheet) {
    sheet = ss.insertSheet(SHEET_NAME);
    const headers = [
      "Datum", "Name Erziehungsber.", "E-Mail", "Telefon", "Adresse",
      "Name des Kindes", "Geburtsdatum", "Klasse",
      "Arabisch", "Koran", "Schüler-ID", "Foto-URL", "Foto-Einwilligung"
    ];
    sheet.appendRow(headers);
    sheet.getRange(1, 1, 1, headers.length)
      .setBackground(CONTRACT_BLUE).setFontColor("#FFFFFF")
      .setFontWeight("bold").setFontSize(10);
    sheet.setFrozenRows(1);
    [140,180,200,140,200,160,110,160,70,70,160,260,120].forEach((w,i)=>
      sheet.setColumnWidth(i+1, w));
  }

  const folder    = getOrCreateFolder(FOLDER_NAME + "/Fotos");
  const timestamp = new Date().toLocaleString("de-DE");
  const p         = data.parent;

  data.children.forEach(ch => {
    const sc     = ch.school || {};
    const hasAr  = sc.key === "Arabisch" || sc.key === "Beide";
    const hasKr  = sc.key === "Koran"    || sc.key === "Beide";
    const ids    = (ch.ids || []).join(" | ");

    // رفع الصورة لـ Drive
    let photoUrl = "—";
    if (ch.photoBase64) {
      try {
        const blob = Utilities.newBlob(
          Utilities.base64Decode(ch.photoBase64), "image/jpeg",
          ch.name.replace(/\s+/g,"_") + ".jpg"
        );
        const file = folder.createFile(blob);
        file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
        photoUrl = file.getUrl();
      } catch(e) { Logger.log("Photo error: " + e); }
    }

    sheet.appendRow([
      timestamp, p.name, p.email, p.phone, p.address,
      ch.name, ch.dob,
      (ch.grade||"—") + (ch.gradeAr ? " / " + ch.gradeAr : ""),
      hasAr ? "✅" : "☐",
      hasKr ? "✅" : "☐",
      ids, photoUrl, "✅ Zugestimmt"
    ]);

    const lr = sheet.getLastRow();
    if (lr % 2 === 0) sheet.getRange(lr,1,1,13).setBackground("#EBF0FA");
  });
}

// ───────────────────────────────────────────────────────────
//  توليد PDF كارت التعريف — بنفس تصميم الملف الأصلي
//  صفحة أفقية كاملة A4 landscape
// ───────────────────────────────────────────────────────────
function generateCardPDF(child, studentId, schoolKey) {
  const isKoran  = schoolKey === "Koran";
  const schoolDe = isKoran ? "Koran-Schule" : "Arabisch-Schule";

  const doc  = DocumentApp.create("Itqan_Karte_" + Date.now());
  const body = doc.getBody();
  body.clear();

  // A4 Landscape: w=842pt h=595pt → in DXA: w=15120 h=10800
  body.setPageWidth(841.89).setPageHeight(595.28);
  body.setMarginTop(0).setMarginBottom(0).setMarginLeft(0).setMarginRight(0);

  const logoBytes = Utilities.base64Decode(LOGO_B64);
  const logoBlob  = Utilities.newBlob(logoBytes, "image/png", "logo.png");

  // ── الجدول الرئيسي: شريط أزرق | محتوى | شريط أزرق ────────
  // الكارت = جدول 1 صف × 3 أعمدة
  const mainTbl = body.appendTable([["", "", ""]]);
  mainTbl.setBorderWidth(0);

  // عرض الأعمدة بالنقاط (842pt إجمالاً)
  mainTbl.setColumnWidth(0, 28);   // شريط أزرق يسار
  mainTbl.setColumnWidth(1, 786);  // المحتوى
  mainTbl.setColumnWidth(2, 28);   // شريط أزرق يمين

  // ── الشريط الأيسر ─────────────────────────────────────────
  const leftCell = mainTbl.getCell(0, 0);
  leftCell.setBackgroundColor(CARD_BLUE_DARK);
  leftCell.getChild(0).asParagraph().editAsText().setText(" ").setFontSize(180);

  // ── المحتوى الرئيسي ───────────────────────────────────────
  const midCell = mainTbl.getCell(0, 1);
  midCell.clear();
  midCell.setBackgroundColor("#FFFFFF");
  midCell.setPaddingTop(20).setPaddingBottom(20)
         .setPaddingLeft(30).setPaddingRight(30);

  // الصف الأول: لوجو + اسم كبير
  const row1 = midCell.appendTable([["", ""]]);
  row1.setBorderWidth(0);
  row1.setColumnWidth(0, 180);
  row1.setColumnWidth(1, 546);

  // لوجو
  const logoCell = row1.getCell(0, 0);
  logoCell.clear();
  logoCell.getChild(0).asParagraph()
    .appendInlineImage(logoBlob).setWidth(150).setHeight(73);

  // الاسم الكبير — يمين
  const nameCell = row1.getCell(0, 1);
  nameCell.clear();
  const namePara = nameCell.getChild(0).asParagraph();
  namePara.setAlignment(DocumentApp.HorizontalAlignment.RIGHT);
  namePara.appendText(child.name);
  namePara.editAsText().setFontSize(36).setBold(true)
    .setForegroundColor(CARD_BLUE_DARK);

  // سطر فاصل
  midCell.appendParagraph(" ").editAsText().setFontSize(4);
  const sepTbl = midCell.appendTable([[""]]);
  sepTbl.setBorderWidth(0);
  sepTbl.getCell(0,0).setBackgroundColor(CARD_BLUE_MID)
    .getChild(0).asParagraph().editAsText().setText(" ").setFontSize(3);
  midCell.appendParagraph(" ").editAsText().setFontSize(8);

  // الصف الثاني: صورة + بيانات
  const row2 = midCell.appendTable([["", ""]]);
  row2.setBorderWidth(0);
  row2.setColumnWidth(0, 200);
  row2.setColumnWidth(1, 526);

  // صورة الطفل
  const photoCell = row2.getCell(0, 0);
  photoCell.clear();
  photoCell.setBackgroundColor("#F2F5FA");
  photoCell.setPaddingTop(10).setPaddingBottom(10)
           .setPaddingLeft(15).setPaddingRight(15);

  if (child.photoBase64) {
    try {
      const imgBlob = Utilities.newBlob(
        Utilities.base64Decode(child.photoBase64), "image/jpeg", "foto.jpg"
      );
      const photoPara = photoCell.getChild(0).asParagraph();
      photoPara.setAlignment(DocumentApp.HorizontalAlignment.CENTER);
      photoPara.appendInlineImage(imgBlob).setWidth(140).setHeight(170);
    } catch(e) {
      photoCell.getChild(0).asParagraph()
        .editAsText().setText("Foto").setFontSize(14)
        .setForegroundColor("#AAAAAA");
    }
  } else {
    const noPhoto = photoCell.getChild(0).asParagraph();
    noPhoto.setAlignment(DocumentApp.HorizontalAlignment.CENTER);
    noPhoto.editAsText().setText("Foto").setFontSize(16)
      .setForegroundColor("#CCCCCC").setBold(false);
  }

  // بيانات الطالب — يمين
  const dataCell = row2.getCell(0, 1);
  dataCell.clear();
  dataCell.setPaddingLeft(30).setPaddingTop(10);

  function addField(label, value, big) {
    // label
    const lp = dataCell.appendParagraph(label + ":");
    lp.editAsText().setFontSize(11).setBold(true)
      .setForegroundColor(CARD_BLUE_MID);
    // value
    const vp = dataCell.appendParagraph(value || "—");
    vp.editAsText().setFontSize(big ? 22 : 15).setBold(big)
      .setForegroundColor(CARD_BLUE_DARK);
    dataCell.appendParagraph(" ").editAsText().setFontSize(5);
  }

  // أول فقرة فارغة — نضع مسافة وليس نصاً فارغاً
  dataCell.getChild(0).asParagraph().editAsText().setText(" ").setFontSize(4);

  addField("Schulklasse", (child.grade||"—") + (child.gradeAr?" / "+child.gradeAr:""), false);
  addField("Schüler-ID",  studentId, true);
  addField("Schule",      schoolDe,  false);

  // سنة دراسية
  const yearPara = dataCell.appendParagraph(YEAR);
  yearPara.editAsText().setFontSize(11).setForegroundColor("#888888").setBold(false);

  // سطر فاصل ثانٍ
  midCell.appendParagraph(" ").editAsText().setFontSize(8);
  const sep2 = midCell.appendTable([[""]]);
  sep2.setBorderWidth(0);
  sep2.getCell(0,0).setBackgroundColor(CARD_BLUE_DARK)
    .getChild(0).asParagraph().editAsText().setText(" ").setFontSize(3);

  // ── الشريط الأيمن ──────────────────────────────────────────
  const rightCell = mainTbl.getCell(0, 2);
  rightCell.setBackgroundColor(CARD_BLUE_DARK);
  rightCell.getChild(0).asParagraph().editAsText().setText(" ").setFontSize(180);

  // ── Export PDF ─────────────────────────────────────────────
  doc.saveAndClose();
  const docId = doc.getId();
  const token = ScriptApp.getOAuthToken();
  const resp  = UrlFetchApp.fetch(
    "https://docs.google.com/document/d/" + docId + "/export?format=pdf",
    { headers: { Authorization: "Bearer " + token }, muteHttpExceptions: true }
  );
  DriveApp.getFileById(docId).setTrashed(true);

  return resp.getBlob().setName(
    "Itqan_Ausweis_" + child.name.replace(/\s+/g,"_") + "_" + studentId + ".pdf"
  );
}

// ── توليد جميع الكروت ──────────────────────────────────────
function generateAllCardPDFs(data) {
  const cards = [];
  data.children.forEach(ch => {
    if (!ch.school) return;
    const ids = ch.ids || [];
    if (ch.school.key === "Beide") {
      cards.push(generateCardPDF(ch, ids[0]||"AR-ID", "Arabisch"));
      cards.push(generateCardPDF(ch, ids[1]||"KR-ID", "Koran"));
    } else {
      cards.push(generateCardPDF(ch, ids[0]||"ID", ch.school.key));
    }
  });
  return cards;
}

// ───────────────────────────────────────────────────────────
//  توليد PDF العقد
// ───────────────────────────────────────────────────────────
function generateContractPDF(data) {
  const doc  = DocumentApp.create("Itqan_Vertrag_" + Date.now());
  const body = doc.getBody();
  body.clear();
  body.setMarginTop(40).setMarginBottom(40).setMarginLeft(60).setMarginRight(60);

  const p         = data.parent;
  const logoBytes = Utilities.base64Decode(LOGO_B64);
  const logoBlob  = Utilities.newBlob(logoBytes, "image/png", "logo.png");

  // ── Header ─────────────────────────────────────────────────
  const hTbl = body.appendTable([["", ""]]);
  hTbl.setBorderWidth(0);
  hTbl.setColumnWidth(0, 130);
  hTbl.setColumnWidth(1, 360);

  const lcell = hTbl.getCell(0,0);
  lcell.clear();
  lcell.getChild(0).asParagraph().appendInlineImage(logoBlob).setWidth(110).setHeight(54);

  const rcell = hTbl.getCell(0,1);
  rcell.clear();
  const rp1 = rcell.getChild(0).asParagraph();
  rp1.setText("Bildungsvertrag");
  rp1.editAsText().setFontSize(22).setBold(true).setForegroundColor(CONTRACT_BLUE);
  rcell.appendParagraph("für den Arabisch- und/oder Koran-Unterricht")
    .editAsText().setFontSize(12).setForegroundColor(CONTRACT_BLUE).setBold(false);
  rcell.appendParagraph("Schuljahr " + YEAR + "  |  Ausgestellt am: " + new Date().toLocaleDateString("de-DE"))
    .editAsText().setFontSize(9).setForegroundColor("#777777").setBold(false);

  // Trennlinie
  body.appendParagraph(" ").editAsText().setFontSize(4);
  const sepT = body.appendTable([[" "]]);
  sepT.setBorderWidth(0);
  sepT.getCell(0,0).setBackgroundColor(CONTRACT_BLUE)
    .getChild(0).asParagraph().editAsText().setText(" ").setFontSize(3);
  body.appendParagraph(" ").editAsText().setFontSize(5);

  // ── Hilfsfunktionen ────────────────────────────────────────
  function secHeader(num, text) {
    body.appendParagraph(" ").editAsText().setFontSize(3);
    const t = body.appendTable([[num + ".   " + text]]);
    t.setBorderWidth(0);
    t.getCell(0,0).setBackgroundColor(CONTRACT_LIGHT)
      .getChild(0).asParagraph().editAsText()
      .setFontSize(11).setBold(true).setForegroundColor(CONTRACT_BLUE);
    body.appendParagraph(" ").editAsText().setFontSize(2);
  }

  function subHdr(text) {
    body.appendParagraph(text).editAsText()
      .setFontSize(10).setBold(true).setForegroundColor(CONTRACT_BLUE);
  }

  function dataRow(label, val, shade) {
    const t = body.appendTable([[label, val||"—"]]);
    t.setBorderWidth(0.3);
    t.setColumnWidth(0, 165); t.setColumnWidth(1, 325);
    const c0 = t.getCell(0,0); const c1 = t.getCell(0,1);
    c0.getChild(0).asParagraph().editAsText().setFontSize(10).setBold(true);
    c1.getChild(0).asParagraph().editAsText().setFontSize(10).setBold(false);
    if (shade) c1.setBackgroundColor("#F5F5F5");
    [c0,c1].forEach(c=>c.setPaddingTop(4).setPaddingBottom(4)
      .setPaddingLeft(6).setPaddingRight(4));
  }

  function check(on, text) {
    body.appendParagraph("  " + (on?"☒":"☐") + "  " + text)
      .editAsText().setFontSize(10);
  }

  function bul(text) {
    body.appendParagraph("   •   " + text).editAsText().setFontSize(10);
  }

  function txt(t) { body.appendParagraph(t).editAsText().setFontSize(10); }
  function gap() { body.appendParagraph(" ").editAsText().setFontSize(4); }

  // ═══ 1. Vertragsparteien ═══════════════════════════════════
  secHeader("1","Vertragsparteien");
  subHdr("Trägerinstitution:");
  dataRow("Name",    "Interkulturelle Gemeinde Berlin e.V.");
  dataRow("Sitz",    "Britzkestr. 10, 12347 Berlin");
  dataRow("E-Mail",  "itqanschule@gmail.com");
  dataRow("Telefon", "0178 8978556");
  gap();
  subHdr("Erziehungsberechtigte/r:");
  dataRow("Name",    p.name,    true);
  dataRow("Adresse", p.address, true);
  dataRow("E-Mail",  p.email,   true);
  dataRow("Telefon", p.phone,   true);
  gap();

  data.children.forEach((ch,i) => {
    subHdr("Kind " + (i+1) + ":");
    dataRow("Name des Kindes", ch.name, true);
    dataRow("Geburtsdatum",    ch.dob,  true);
    dataRow("Schulklasse",
      (ch.grade||"—") + (ch.gradeAr?" / "+ch.gradeAr:""), true);
    dataRow("Schüler-ID", (ch.ids||[]).join("  |  "), true);
    if (i < data.children.length-1) gap();
  });

  // ═══ 2. Unterrichtsform ════════════════════════════════════
  secHeader("2","Unterrichtsform und Wahl der Kurse");
  data.children.forEach((ch,i) => {
    if (data.children.length > 1)
      body.appendParagraph("  ► " + ch.name).editAsText()
        .setFontSize(10).setBold(true).setItalic(true);
    const sc = ch.school ? ch.school.key : "";
    check(sc==="Arabisch"||sc==="Beide",
      "Arabischunterricht – für Muttersprachler (350 €/Jahr/Kind)");
    check(sc==="Koran"||sc==="Beide",
      "Koranunterricht – Rezitation und Auswendiglernen (200 €/Jahr/Kind)");
    check(sc==="Beide",
      "Beide Kurse – Arabisch + Koran (550 €/Jahr/Kind)");
    if (i < data.children.length-1) gap();
  });

  // ═══ 3. Unterrichtszeitraum ════════════════════════════════
  secHeader("3","Unterrichtszeitraum und Ferienregelung");
  const hasKr = data.children.some(c=>c.school&&(c.school.key==="Koran"||c.school.key==="Beide"));
  const hasAr = data.children.some(c=>c.school&&(c.school.key==="Arabisch"||c.school.key==="Beide"));
  const sjP = body.appendParagraph("");
  sjP.editAsText().appendText("Schuljahr:  ").setBold(true).setFontSize(10)
    .appendText("September 2026 – Juni 2027").setBold(false).setFontSize(10);
  body.appendParagraph("Beginn des Unterrichts:").editAsText().setBold(true).setFontSize(10);
  check(hasKr,  "Freitagskurse (Koran): ab 04.09.2026");
  check(hasAr,  "Samstagskurse (Arabisch): ab 05.09.2026");
  check(false,  "Sonntagskurse (Arabisch): ab 06.09.2026");

  // ═══ 4. Teilnahmevoraussetzungen ═══════════════════════════
  secHeader("4","Teilnahmevoraussetzungen");
  txt("Die Anmeldung ist erst gültig, wenn:");
  bul("der erste Elternabend vor Schuljahresbeginn besucht wurde");
  bul("die Kursgebühren entrichtet wurden");
  bul("das Anmeldeformular vollständig ausgefüllt vorliegt");

  // ═══ 5. Zahlungsbedingungen ════════════════════════════════
  secHeader("5","Zahlungsbedingungen");
  const totalFees = data.children.reduce((s,ch)=>s+(ch.school?ch.school.fee:0),0);
  body.appendParagraph("Gebühren:").editAsText().setBold(true).setFontSize(10);
  bul("Arabischunterricht: 350 €/Jahr/Kind");
  bul("Koranunterricht: 200 €/Jahr/Kind");
  bul("Beide Kurse: 550 €/Jahr/Kind");
  gap();
  const gesPara = body.appendParagraph("");
  gesPara.editAsText()
    .appendText("Gesamtbetrag: ").setBold(true).setFontSize(11)
    .appendText(totalFees + " €/Jahr").setBold(true).setFontSize(11)
    .setForegroundColor(CONTRACT_BLUE);
  gap();
  body.appendParagraph("Zahlungsoptionen:").editAsText().setBold(true).setFontSize(10);
  check(true,  "In 4 Raten");
  check(false, "Halbjährlich");
  check(false, "Jährlich (Im Voraus)");
  gap();
  body.appendParagraph("Bankverbindung:").editAsText().setBold(true).setFontSize(10);
  dataRow("Kontoinhaber",     "ITQAN");
  dataRow("IBAN",             "DE23 5176 2434 0016 3591 22");
  dataRow("BIC",              "GENODE51BIK");
  dataRow("Verwendungszweck", "Name des Kindes / " + YEAR);

  // ═══ 6. Foto-Einwilligung ══════════════════════════════════
  secHeader("6","Foto- und Videoeinwilligung");
  txt("Mit der Unterzeichnung dieses Vertrages erklärt sich der/die Erziehungsberechtigte " +
      "damit einverstanden, dass Fotos und Videos des Kindes, die während der " +
      "Schulaktivitäten, Veranstaltungen und Ausflüge aufgenommen werden, für interne " +
      "Dokumentationszwecke sowie für die Öffentlichkeitsarbeit der Itqan Schule " +
      "(z. B. Website, Social Media, Druckmaterialien) verwendet werden dürfen.");
  gap();
  check(true, "Ich stimme zu");

  // ═══ 7. Vertragsdauer ══════════════════════════════════════
  secHeader("7","Vertragsdauer und Kündigung");
  bul("Der Vertrag gilt bis zum Ende des Schuljahres (Juni 2027).");
  bul("Ordentliche Kündigung: schriftlich bis 30.06.2027");
  bul("Außerordentliche Kündigung: schriftlich 4 Wochen vor Semesterende");
  bul("Fristlose Kündigung bei: Zahlungsverzug über 2 Monate oder unentschuldigtem " +
      "Fehlen an 3 Tagen pro Semester");

  // ═══ 8. Haftung ════════════════════════════════════════════
  secHeader("8","Haftung & Aufsicht");
  txt("Die Schule haftet nicht für verlorene Gegenstände oder Unfälle außerhalb der " +
      "Unterrichtszeiten. Während des Unterrichts besteht Aufsichtspflicht.");

  // ═══ 9. Datenschutz ════════════════════════════════════════
  secHeader("9","Datenschutz");
  txt("Daten werden gemäß DSGVO ausschließlich zur Durchführung und Verwaltung des " +
      "Unterrichts gespeichert und nicht an Dritte weitergegeben.");

  // ═══ 10. Salvatorische Klausel ═════════════════════════════
  secHeader("10","Salvatorische Klausel");
  txt("Sollte eine Klausel dieses Vertrages unwirksam sein, so bleibt die Wirksamkeit " +
      "der übrigen Regelungen unberührt.");

  // ═══ 11. Vertragsunterzeichnung ════════════════════════════
  secHeader("11","Vertragsunterzeichnung");
  const dtP = body.appendParagraph("");
  dtP.editAsText()
    .appendText("Ort, Datum:  ").setBold(true).setFontSize(10)
    .appendText("Berlin,  " + new Date().toLocaleDateString("de-DE"))
    .setBold(false).setFontSize(10);
  gap(); gap();

  const signT = body.appendTable([["Erziehungsberechtigte/r 1","Erziehungsberechtigte/r 2"]]);
  signT.setBorderWidth(0);
  signT.setColumnWidth(0,245); signT.setColumnWidth(1,245);
  [0,1].forEach(ci => {
    const c = signT.getCell(0,ci);
    c.getChild(0).asParagraph().editAsText().setFontSize(9).setForegroundColor("#555555");
    c.appendParagraph(" ").editAsText().setFontSize(18);
    c.appendParagraph("─".repeat(38)).editAsText()
      .setFontSize(9).setForegroundColor("#AAAAAA");
  });
  gap();

  // Footer
  const ftT = body.appendTable([[" "]]);
  ftT.setBorderWidth(0);
  const ftC = ftT.getCell(0,0);
  ftC.setBackgroundColor(CONTRACT_BLUE);
  const ftP = ftC.getChild(0).asParagraph();
  ftP.setText("Itqan Schule  |  Britzkestraße 10, 12347 Berlin  |  itqanschule@gmail.com  |  0178 8978556  |  Schuljahr " + YEAR);
  ftP.setAlignment(DocumentApp.HorizontalAlignment.CENTER);
  ftP.editAsText().setFontSize(8).setForegroundColor("#FFFFFF").setBold(false);

  // Export
  doc.saveAndClose();
  const docId = doc.getId();
  const token = ScriptApp.getOAuthToken();
  const resp  = UrlFetchApp.fetch(
    "https://docs.google.com/document/d/" + docId + "/export?format=pdf",
    { headers: { Authorization: "Bearer " + token }, muteHttpExceptions: true }
  );
  DriveApp.getFileById(docId).setTrashed(true);
  return resp.getBlob().setName(
    "Itqan_Bildungsvertrag_" + p.name.replace(/\s+/g,"_") + "_" + YEAR.replace("/","_") + ".pdf"
  );
}

