// ───────────────────────────────────────────────────────────
function getOrCreateFolder(path) {
  let folder = DriveApp.getRootFolder();
  path.split("/").forEach(name => {
    const found = folder.getFoldersByName(name);
    folder = found.hasNext() ? found.next() : folder.createFolder(name);
  });
  return folder;
}
